DO $$ BEGIN
    INSERT INTO public.challenges (id, title, description, difficulty, category, language, repo_url, code, code_smell, status, created_at)
    VALUES ('ch-xss', 'XSS en Comentarios', 'Este componente renderiza comentarios de usuarios directamente con innerHTML, sin sanitizar. Un usuario malicioso puede inyectar scripts arbitrarios que se ejecutarán en el navegador de otros usuarios.', 'junior', 'security', 'typescript', 'https://github.com/example/social-app', 'import { Component, Input } from ''@angular/core'';\n\n@Component({\n  selector: ''comment-thread'',\n  template: ''<div [innerHTML]="renderComment()"></div>''\n})\nexport class CommentThread {\n  @Input() comments: Comment[] = [];\n\n  renderComment(): string {\n    return this.comments\n      .map(c => `<div class="comment">${c.body}</div>`)\n      .join('''');\n  }\n}', 'Cross-Site Scripting', 'available', '2025-01-02T00:00:00Z')
